parameters.jsCode:
const raw = $('Start').first().json;
let task = '';
try {
  const parsed = JSON.parse(raw.query || '{}');
  task = parsed.task || parsed.description || parsed.query || raw.query || '';
} catch (error) {
  task = raw.task || raw.query || String(raw);
}
task = task.replace(/^task:\s*/i, '').trim();
let docsContext = '';
try {
  const searchResults = $('Search API Docs').first().json;
  const topResults = (searchResults?.results || []).slice(0, 3).map(r => `- ${r.title}: ${r.url}`).join('
');
  const docText = $('Fetch Doc Content').first().json?.body || $('Fetch Doc Content').first().json?.data || '';
  const truncated = String(docText).substring(0, 8000).trim();
  if (truncated && truncated.length > 100) {
    docsContext = `

API DOCUMENTATION:
Sources:
${topResults}

Content:
${truncated}`;
  } else if (topResults) {
    docsContext = `

Found sources:
${topResults}`;
  }
} catch (error) {
  docsContext = '';
}
const words = task.toLowerCase().split(/\s+/).filter(w => w.length > 2 && !['the','and','for','with','from','build','create','tool','server','mcp','api','new'].includes(w));
const serverName = words.slice(0, 3).map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ') || 'Custom Tool';
const path = words.slice(0, 2).join('-') || 'custom-tool';
const prompt = `Generate JavaScript for an n8n sub-workflow that handles an external API request.

TASK: ${task}${docsContext}

The code runs inside an n8n Code node. Parameters arrive through $json.

Reply ONLY with a JSON object:
{
  "tool_name": "snake_case_name",
  "description": "What the tool does in one sentence",
  "params": [{"name": "param1", "description": "what it means", "type": "string"}],
  "jsCode": "the JavaScript code"
}

RULES for jsCode (n8n Code node, not toolCode):
- Read parameters with const isbn = $json.isbn || $input.first().json.isbn;
- Use HTTP with await helpers.httpRequest({method:'GET', url:'...'})
- Return an array: return [{json: {result: 'string response'}}];
- Do not use fetch(), require(), or new URL()
- Include error handling

Reply ONLY with the JSON object.`;
return [{ json: { prompt, task, serverName, path } }];

const llmRaw = $input.first().json.text || $input.first().json.response || '';
const meta = $('BuildPrompt').first().json;

let toolDef;
try {
  const jsonMatch = llmRaw.match(/\{[\s\S]*\}/);
  toolDef = JSON.parse(jsonMatch[0]);
} catch(e) {
  return [{json: {error: 'JSON parse failed', raw: llmRaw.substring(0,500)}}];
}

const toolName = toolDef.tool_name || 'custom_tool';
const description = toolDef.description || meta.task;
const jsCode = toolDef.jsCode || '';
const params = toolDef.params || [];

// sampleArgs for testing
const sampleObj = {};
params.forEach(p => { sampleObj[p.name || p] = 'test'; });

// Sub-workflow JSON: Execute Workflow Trigger + Code node
const subWorkflow = {
  name: 'MCP Sub: ' + meta.serverName,
  settings: {callerPolicy: 'workflowsFromSameOwner'},
  nodes: [
    {
      id: 'sub-trigger',
      name: 'Execute Workflow Trigger',
      type: 'n8n-nodes-base.executeWorkflowTrigger',
      typeVersion: 1.1,
      position: [0, 0],
      parameters: {inputSource: 'passthrough'}
    },
    {
      id: 'sub-code',
      name: 'Run Tool',
      type: 'n8n-nodes-base.code',
      typeVersion: 2,
      position: [256, 0],
      parameters: {language: 'javaScript', jsCode: jsCode}
    }
  ],
  connections: {
    'Execute Workflow Trigger': {main: [[{node: 'Run Tool', type: 'main', index: 0}]]}
  }
};

// MCP server workflow: mcpTrigger + toolWorkflow pointing to sub-workflow
// (sub-workflow ID filled in after sub is created)
const workflowInputsSchema = params.map(p => ({
  id: p.name || p,
  displayName: p.name || p,
  type: (p.type || 'string'),
  description: p.description || '',
  required: true,
  defaultMatch: false,
  display: true,
  canBeUsedToMatch: true,
  removed: false
}));

const workflowInputsValue = {};
params.forEach(p => {
  const pname = p.name || p;
  workflowInputsValue[pname] = `={{ $fromAI('${pname}', '${p.description || pname}', '${p.type || 'string'}') }}`;
});

return [{json: {
  subWorkflow: JSON.stringify(subWorkflow),
  toolName,
  description,
  path: meta.path,
  serverName: meta.serverName,
  sampleArgs: JSON.stringify(sampleObj),
  workflowInputsSchema: JSON.stringify(workflowInputsSchema),
  workflowInputsValue: JSON.stringify(workflowInputsValue),
  originalJsCode: jsCode
}}];

const summary = $('Result').first().json;
const registry = $('Register MCP').first()?.json;
const agentUpdate = $('Build Instructions').first()?.json;
const registryText = registry?.path ? `Registry: saved ${registry.path}` : 'Registry: update attempted';
const agentText = agentUpdate?.serverCount > 0 ? `Agent config refreshed (${agentUpdate.serverCount} MCP servers known)` : 'Agent config refresh could not be confirmed';
return [{ json: {
  response: summary.response + '\n\n' + registryText + '\n' + agentText,
  workflow_id: summary.workflow_id,
  mcp_path: summary.mcp_path,
  tool_name: summary.tool_name
} }];

const servers = $input.all().map(i => i.json);
if (!servers.length) return [{ json: { instructions: null, serverCount: 0 } }];
const lines = servers.map(server => {
  const tools = Array.isArray(server.tools) ? server.tools.join(', ') : (server.tools || '?');
  return `- ${server.server_name}: ${server.mcp_url} (Tool: ${tools}) - ${server.description || ''}`;
});
const instructions = `You have MCP (Model Context Protocol) capabilities.

## MCP Client (mcp_client tool)
Use it to call tools on MCP servers. Parameters:
- mcp_url
- tool_name
- arguments (JSON object)

## MCP Builder (mcp_builder tool)
Use it to build new MCP server workflows. Parameter:
- task: what the server should do

## Currently available MCP servers (${servers.length} total):
${lines.join('
')}

## Registry
All active servers are stored in mcp_registry.`;
return [{ json: { instructions, serverCount: servers.length } }];

const activated = $('Patch Tool Schema').first().json;
const assembled = $('Assemble & Deploy').first().json;
const workflowId = activated.id;
const path = assembled.path;
const toolName = assembled.toolName;
let sampleArgs;
try { sampleArgs = JSON.parse(assembled.sampleArgs || '{}'); } catch(e) { sampleArgs = {}; }
const mcpUrl = (process.env.N8N_INTERNAL_URL || 'http://127.0.0.1:5678').replace(/\/$/, '') + '/mcp/' + path;

try {
  const init = await helpers.httpRequest({
    method:'POST', url:mcpUrl,
    headers:{'Content-Type':'application/json','Accept':'application/json, text/event-stream'},
    body:JSON.stringify({jsonrpc:'2.0',id:1,method:'initialize',params:{protocolVersion:'2024-11-05',capabilities:{},clientInfo:{name:'test',version:'1.0'}}}),
    returnFullResponse:true, encoding:'utf-8', json:false
  });
  const sid = init.headers['mcp-session-id'];
  if (!sid) return [{json:{success:false,error:'No session ID — webhook registration may require a deactivate/activate cycle in the UI',workflowId,toolName,path,sampleArgs:assembled.sampleArgs}}];
  await helpers.httpRequest({method:'POST',url:mcpUrl,headers:{'Content-Type':'application/json','Accept':'application/json, text/event-stream','mcp-session-id':sid},body:JSON.stringify({jsonrpc:'2.0',method:'notifications/initialized'}),json:false});
  const resp = await helpers.httpRequest({method:'POST',url:mcpUrl,headers:{'Content-Type':'application/json','Accept':'application/json, text/event-stream','mcp-session-id':sid},body:JSON.stringify({jsonrpc:'2.0',id:2,method:'tools/call',params:{name:toolName,arguments:sampleArgs}}),json:false});
  const dataLine = String(resp).split('\n').find(l => l.startsWith('data: '));
  if (!dataLine) return [{json:{success:false,error:'No response: '+String(resp).substring(0,200),workflowId,toolName,path,sampleArgs:assembled.sampleArgs}}];
  const result = JSON.parse(dataLine.substring(6));
  const content = result.result?.content?.[0]?.text || '';
  if (content.includes('Error:') || result.error) {
    return [{json:{success:false,error:content||JSON.stringify(result.error),workflowId,toolName,path,sampleArgs:assembled.sampleArgs}}];
  }
  return [{json:{success:true,response:content,workflowId,toolName,path}}];
} catch(e) {
  return [{json:{success:false,error:e.message,workflowId,toolName,path,sampleArgs:assembled.sampleArgs}}];
}

const test = $input.first().json;
const assembled = $('Assemble & Deploy').first().json;
let schemaStr = '';
try { schemaStr = JSON.stringify(JSON.parse(test.inputSchema || '{}'), null, 2); } catch (error) { schemaStr = test.inputSchema || '{}'; }
const prompt = `An n8n MCP tool failed its self-test.

ERROR: ${test.error}

TOOL NAME: ${test.toolName}
TEST PARAMETERS: ${test.sampleArgs}

CURRENT INPUT_SCHEMA:
${schemaStr}

CURRENT JSCODE:
${assembled.originalJsCode}

Analyse the failure and return corrected JavaScript code only.
Rules:
- Read parameters with query.param_name
- Use await helpers.httpRequest({method:'GET', url:'...'})
- Do not use fetch(), require(), or new URL()
- Return a plain string

Reply ONLY with corrected JavaScript code.`;
return [{ json: { prompt, toolName: test.toolName, workflowId: test.workflowId, path: test.path, sampleArgs: test.sampleArgs, inputSchema: test.inputSchema } }];

const llmOutput = $input.first().json.text || '';
const meta = $('Build Fix Prompt').first().json;
const apiKey = process.env.N8N_API_KEY || '';
const baseUrl = (process.env.N8N_INTERNAL_URL || 'http://127.0.0.1:5678').replace(/\/$/, '');
let newJsCode = (llmOutput || '').trim().replace(/^```(javascript|js)?\n?/, '').replace(/\n?```$/, '').trim();
if (!newJsCode) return [{ json: { success: false, error: 'LLM returned an empty fix', workflowId: meta.workflowId, path: meta.path, fixApplied: false } }];
const workflow = await helpers.httpRequest({
  method: 'GET',
  url: `${baseUrl}/api/v1/workflows/${meta.workflowId}`,
  headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' }
});
const nodes = workflow.nodes.map((node) => {
  if (node.parameters && node.parameters.name === meta.toolName) {
    node.parameters.jsCode = newJsCode;
    node.parameters.specifyInputSchema = false;
  }
  return node;
});
await helpers.httpRequest({
  method: 'PUT',
  url: `${baseUrl}/api/v1/workflows/${meta.workflowId}`,
  headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
  body: JSON.stringify({ name: workflow.name, nodes, connections: workflow.connections, settings: workflow.settings || {} })
});
const mcpUrl = `${baseUrl}/mcp/${meta.path}`;
let sampleArgs;
try { sampleArgs = JSON.parse(meta.schemaExample || meta.sampleArgs || '{}'); } catch (error) { sampleArgs = {}; }
try {
  const init = await helpers.httpRequest({
    method: 'POST',
    url: mcpUrl,
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json, text/event-stream' },
    body: JSON.stringify({ jsonrpc: '2.0', id: 1, method: 'initialize', params: { protocolVersion: '2024-11-05', capabilities: {}, clientInfo: { name: 'test', version: '1.0' } } }),
    returnFullResponse: true,
    encoding: 'utf-8',
    json: false
  });
  const sid = init.headers['mcp-session-id'];
  if (!sid) return [{ json: { success: false, error: 'No session ID after fix', fixApplied: true, workflowId: meta.workflowId, path: meta.path, toolName: meta.toolName } }];
  await helpers.httpRequest({ method: 'POST', url: mcpUrl, headers: { 'Content-Type': 'application/json', 'Accept': 'application/json, text/event-stream', 'mcp-session-id': sid }, body: JSON.stringify({ jsonrpc: '2.0', method: 'notifications/initialized' }), json: false });
  const resp = await helpers.httpRequest({ method: 'POST', url: mcpUrl, headers: { 'Content-Type': 'application/json', 'Accept': 'application/json, text/event-stream', 'mcp-session-id': sid }, body: JSON.stringify({ jsonrpc: '2.0', id: 2, method: 'tools/call', params: { name: meta.toolName, arguments: sampleArgs } }), json: false });
  const dataLine = String(resp).split('\n').find((line) => line.startsWith('data: '));
  if (!dataLine) return [{ json: { success: false, error: 'No data after fix', fixApplied: true, workflowId: meta.workflowId, path: meta.path, toolName: meta.toolName } }];
  const result = JSON.parse(dataLine.substring(6));
  const content = result.result?.content?.[0]?.text || '';
  const ok = !content.startsWith('Error:') && !result.error;
  return [{ json: { success: ok, response: content, fixApplied: true, workflowId: meta.workflowId, path: meta.path, toolName: meta.toolName } }];
} catch (error) {
  return [{ json: { success: false, error: 'Retest: ' + error.message, fixApplied: true, workflowId: meta.workflowId, path: meta.path, toolName: meta.toolName } }];
}

const mcpCreated = $('Create MCP Workflow').first().json;
const assembled = $('Assemble & Deploy').first().json;
const subId = $('Create Sub-Workflow').first().json.id;
const testResult = $input.first().json;
const publicBaseUrl = (process.env.WEBHOOK_URL || '').replace(/\/$/, '');
const testStatus = testResult.success
  ? `Self-test passed: ${(testResult.response || '').substring(0, 100)}`
  : `Self-test failed: ${(testResult.error || '').substring(0, 100)}`;
return [{ json: {
  response: `MCP server created.\nMCP Workflow: ${mcpCreated.name} (ID: ${mcpCreated.id})\nSub-workflow ID: ${subId}\nMCP path: /mcp/${assembled.path}\nTool: ${assembled.toolName}\nURL: ${publicBaseUrl}/mcp/${assembled.path}\n\n${testStatus}\n\nIf the webhook does not answer immediately, deactivate and reactivate the workflow once in the n8n UI.`,
  workflow_id: mcpCreated.id,
  sub_workflow_id: subId,
  mcp_path: assembled.path,
  tool_name: assembled.toolName,
  test_success: testResult.success
} }];

const subId = $('Create Sub-Workflow').first().json.id;
const apiKey = process.env.N8N_API_KEY || '';
const baseUrl = (process.env.N8N_INTERNAL_URL || 'http://127.0.0.1:5678').replace(/\/$/, '');
await helpers.httpRequest({
  method: 'POST',
  url: `${baseUrl}/api/v1/workflows/${subId}/activate`,
  headers: { 'X-N8N-API-KEY': apiKey }
});
return [{ json: { subId, activated: true } }];

const subId = $('Create Sub-Workflow').first().json.id;
const assembled = $('Assemble & Deploy').first().json;
const toolName = assembled.toolName;
const description = assembled.description;
const serverName = assembled.serverName;
const path = assembled.path;
const workflowInputsValue = JSON.parse(assembled.workflowInputsValue || '{}');
const workflowInputsSchema = JSON.parse(assembled.workflowInputsSchema || '[]');

const mcpWorkflow = {
  name: 'MCP: ' + serverName,
  settings: {},
  nodes: [
    {
      id: 'mcp-trigger',
      name: 'MCP Server Trigger',
      type: '@n8n/n8n-nodes-langchain.mcpTrigger',
      typeVersion: 2,
      position: [0, 0],
      parameters: {path: path, authentication: 'none'}
    },
    {
      id: 'tool-wf',
      name: toolName,
      type: '@n8n/n8n-nodes-langchain.toolWorkflow',
      typeVersion: 2.2,
      position: [0, 300],
      parameters: {
        name: toolName,
        description: description,
        workflowId: {__rl: true, value: subId, mode: 'id'},
        workflowInputs: {
          mappingMode: 'defineBelow',
          value: workflowInputsValue,
          matchingColumns: [],
          schema: workflowInputsSchema,
          attemptToConvertTypes: false,
          convertFieldsToString: false
        }
      }
    }
  ],
  connections: {}
};
mcpWorkflow.connections[toolName] = {ai_tool: [[{node: 'MCP Server Trigger', type: 'ai_tool', index: 0}]]};

return [{json: {mcpWorkflowJson: JSON.stringify(mcpWorkflow), subId, toolName, path, serverName}}];
